/**
 * @summary Delete a participant KYC record
 */
export const getDeleteOnboardingParticipantUrl = (
  projectId: string,
  role: "landowner" | "developer" | "investor" | "partner" | "other",
  params?: DeleteOnboardingParticipantParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/projects/${projectId}/onboarding/participants/${role}?${stringifiedParams}`
    : `/api/projects/${projectId}/onboarding/participants/${role}`;
};

